// 读取当前文档全部段落内容
var doc = Application.ActiveDocument;
var content = '';
for (var i = 0; i < doc.Sections.Count; i++) {
  var section = doc.Sections[i];
  for (var j = 0; j < section.Paragraphs.Count; j++) {
    var para = section.Paragraphs[j];
    if (para.Range.Text.trim()) {
      content += para.Range.Text.trim() + '\n';
    }
  }
}
return content.substring(0, 15000);

// 读取当前文档全部段落内容（修正API调用方式）
var doc = Application.ActiveDocument;
var content = '';
var paragraphs = doc.Paragraphs;
for (var i = 0; i < paragraphs.Count; i++) {
  var para = paragraphs[i];
  if (para.Range && para.Range.Text.trim()) {
    content += para.Range.Text.trim() + '\n';
  }
}
return content.substring(0, 15000);

// 读取当前文档全部段落内容（使用Range.Text直接获取）
var doc = Application.ActiveDocument;
var content = '';
var paragraphs = doc.Paragraphs;
for (var i = 1; i <= paragraphs.Count; i++) {
  var para = paragraphs.Item(i);
  if (para && para.Range) {
    var text = para.Range.Text;
    // 去除末尾的段落标记
    if (text.length > 0 && (text[text.length-1] === '\r' || text[text.length-1] === '\n')) {
      text = text.substring(0, text.length - 1);
    }
    if (text.trim()) {
      content += text.trim() + '\n';
    }
  }
}
return content.substring(0, 15000);
